from instructor import from_openai

class OptimizedDocumentExtractor:
    def __init__(self, client):
        self.instructor = from_openai(client)

    def extract_with_hybrid_retrieval(self, query: str, retriever):
        # Extract schema hints for retrieval
        schema_hints = ['title', 'entities', 'contract', 'invoice', 'receipt']

        # Hybrid query: original + schema hints
        hybrid_query = f"{query} {' '.join(schema_hints)}"

        context = retriever.retrieve(hybrid_query, k=5)

        return self.instructor.chat.completions.create(
            model='gpt-4o-mini',
            response_model=Document,
            messages=[
                {'role': 'system', 'content': 
                 'Use ONLY information from context. Do not hallucinate.'},
                {'role': 'user', 'content': f"Context: {context}\nQuery: {query}"}
            ],
            temperature=0.1,  # Lower temp for consistency
            max_retries=5
        )

from typing import Literal

class Document(BaseModel):
    title: str
    entities: list[str]
    category: Literal['contract', 'invoice', 'receipt']

VALID_CATEGORIES = ['contract', 'invoice', 'receipt']

@client.chat.completions.create
def extract_with_fallback(client, context: str, query: str) -> Document:
    fallback_prompt = f"""
Context: {context}

Valid categories: {', '.join(VALID_CATEGORIES)}
Examples:
- Invoice: payment documents
- Contract: agreements
- Receipt: transaction proof

Query: {query}

Extract ONLY from context using valid categories above.
"""

    return client.chat.completions.create(
        model='gpt-4o-mini',
        response_model=Document,
        messages=[{'role': 'user', 'content': fallback_prompt}],
        partial=False,  # Fail fast on partial extraction
        max_retries=3
    )

class NestedDocument(BaseModel):
    title: str
    metadata: dict
    sections: list['Section']

class Section(BaseModel):
    heading: str
    content: str
    category: Literal['terms', 'pricing', 'signature']

@client.chat.completions.create
def staged_nested_extraction(client, context: str) -> NestedDocument:
    # Stage 1: Extract top-level structure
    structure = client.chat.completions.create(
        model='gpt-4o-mini',
        response_model=dict,
        messages=[{'role': 'user', 'content': f"List sections in: {context}"}],
    )

    # Stage 2: Extract each section individually
    sections = []
    for section_info in structure.get('sections', []):
        section_context = extract_section_context(context, section_info['heading'])
        section = client.chat.completions.create(
            response_model=Section,
            messages=[{'role': 'user', 'content': f"{section_context}"}],
        )
        sections.append(section)

    return NestedDocument(
        title=structure['title'],
        metadata=structure['metadata'],
        sections=sections
    )
